<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Burnfront</title>
<meta name="viewport" content="width=device-width, initial-scale=1">
<style>
  @font-face{
    font-family:'Staatliches';
    src:url(data:font/woff2;base64,) format('woff2');
    font-weight:400;font-style:normal;font-display:block;
  }
  :root{
    --soot:#171310;
    --char:#221c15;
    --char-2:#2c2519;
    --line:#3b3325;
    --ash:#a89d8c;
    --ash-dim:#6e6558;
    --paper:#f3ead9;
    --ember:#ff8a3d;
    --ember-deep:#e06a1f;
    --flame:#ffd86b;
    --danger:#e5484d;
    --cell-max:540px;
    font-size:16px;
  }
  *{box-sizing:border-box}
  html,body{margin:0;padding:0}
  body{
    background:var(--soot);
    color:var(--ash);
    font-family:system-ui,-apple-system,"Segoe UI",Roboto,sans-serif;
    line-height:1.55;
    -webkit-font-smoothing:antialiased;
    background-image:radial-gradient(1200px 500px at 50% -10%, rgba(255,138,61,.05), transparent 65%);
  }
  main{max-width:640px;margin:0 auto;padding:40px 16px 64px;display:flex;flex-direction:column;gap:28px}

  /* ---------- masthead ---------- */
  .masthead{display:flex;flex-direction:column;gap:8px}
  .eyebrow{
    margin:0;font-size:11px;letter-spacing:.22em;text-transform:uppercase;
    color:var(--ash-dim);
  }
  h1{
    margin:0;font-family:'Staatliches',system-ui,sans-serif;font-weight:400;
    font-size:clamp(52px,11vw,76px);line-height:.95;letter-spacing:.035em;
    color:var(--paper);text-wrap:balance;
  }
  h1 .spark-mark{color:var(--flame);text-shadow:0 0 18px rgba(255,216,107,.45)}
  .lede{margin:2px 0 0;max-width:46ch;color:var(--ash)}

  /* ---------- toolbar ---------- */
  .toolbar{display:flex;flex-wrap:wrap;gap:10px;align-items:center}
  .seg{display:flex;border:1px solid var(--line);border-radius:5px;overflow:hidden}
  .seg button{
    appearance:none;background:none;border:0;padding:8px 12px;cursor:pointer;
    color:var(--ash-dim);font:600 11px/1 system-ui,sans-serif;
    letter-spacing:.09em;text-transform:uppercase;white-space:nowrap;
  }
  .seg button + button{border-left:1px solid var(--line)}
  .seg button.on{color:var(--ember);background:rgba(255,138,61,.08)}
  .seg button:hover:not(.on){color:var(--ash)}
  .btn{
    appearance:none;background:none;cursor:pointer;
    border:1px solid var(--line);border-radius:5px;padding:8px 14px;
    color:var(--ash);font:600 11px/1 system-ui,sans-serif;
    letter-spacing:.09em;text-transform:uppercase;
  }
  .btn:hover{border-color:var(--ember);color:var(--paper)}
  .btn:disabled{opacity:.35;cursor:default}
  .btn:disabled:hover{border-color:var(--line);color:var(--ash)}
  .btn.primary{border-color:var(--ember-deep);color:var(--ember)}
  .btn.primary:hover{background:rgba(255,138,61,.1);color:var(--flame)}
  button:focus-visible,.seg button:focus-visible{outline:2px solid var(--flame);outline-offset:2px}

  .chips{display:flex;gap:10px;margin-left:auto}
  .chip{
    border:1px solid var(--line);border-radius:5px;padding:8px 12px;
    font-size:12px;font-variant-numeric:tabular-nums;color:var(--ash);
    display:flex;gap:7px;align-items:baseline;white-space:nowrap;
  }
  .chip .k{font-size:10px;letter-spacing:.14em;text-transform:uppercase;color:var(--ash-dim)}
  .chip .v{color:var(--paper);font-weight:600}
  .chip.over .v{color:var(--danger)}

  /* ---------- board ---------- */
  .board-wrap{position:relative}
  .grid{
    display:grid;gap:5px;width:min(92vw,var(--cell-max));
    touch-action:manipulation;
  }
  .cell{
    appearance:none;padding:0;border:1px solid var(--line);border-radius:5px;
    background:var(--char);aspect-ratio:1;cursor:pointer;position:relative;
    color:var(--paper);
    font-family:'Staatliches',system-ui,sans-serif;
    font-size:min(calc(84vw / var(--cols) * .44), calc(var(--cell-max) / var(--cols) * .44));
    line-height:1;
    transition:background-color .35s ease,color .35s ease,border-color .2s ease;
  }
  .cell:not(.fixed):hover{border-color:var(--ash-dim)}
  .cell:focus-visible{outline:2px solid var(--flame);outline-offset:1px;z-index:1}
  .cell.fixed{cursor:default}
  .cell.spark{color:var(--flame);text-shadow:0 0 14px rgba(255,216,107,.5);background:var(--char-2)}
  .cell.clue{background:var(--char-2)}
  .cell.break{
    background:repeating-linear-gradient(135deg,#564b38 0 3px,#241f16 3px 9px);
    border-color:#6e6146;
  }
  .cell.dot::after{
    content:"";position:absolute;inset:0;margin:auto;width:12%;height:12%;
    border-radius:50%;background:var(--ash);opacity:.9;
  }
  .cell .min{
    position:absolute;inset:0;display:flex;align-items:center;justify-content:center;
  }
  /* burn replay */
  .cell.burn{background:var(--burn-bg,var(--ember));border-color:transparent;color:var(--soot);text-shadow:none}
  .cell.burn.spark{color:#5a1d00}
  .grid.done .cell{cursor:default}

  .under{display:flex;align-items:baseline;gap:12px;min-height:44px;margin-top:14px}
  .hint{margin:0;font-size:13px;color:var(--ash-dim);max-width:60ch}
  .banner{display:none;flex-direction:column;gap:6px}
  .banner.show{display:flex}
  .banner .headline{
    font-family:'Staatliches',system-ui,sans-serif;font-size:30px;letter-spacing:.05em;
    color:var(--flame);line-height:1;
  }
  .banner p{margin:0;font-size:14px;color:var(--ash)}
  .banner .v{color:var(--paper);font-variant-numeric:tabular-nums}

  .veil{
    position:absolute;inset:0;display:none;align-items:center;justify-content:center;
    background:rgba(23,19,16,.72);backdrop-filter:blur(1px);border-radius:6px;z-index:2;
  }
  .veil.show{display:flex}
  .veil span{
    font-size:12px;letter-spacing:.18em;text-transform:uppercase;color:var(--ash);
    animation:pulse 1.2s ease-in-out infinite;
  }
  @keyframes pulse{0%,100%{opacity:.45}50%{opacity:1}}

  /* ---------- how it works ---------- */
  .learn{display:flex;flex-direction:column;gap:16px}
  .learn h2{
    margin:0;font-family:'Staatliches',system-ui,sans-serif;font-weight:400;
    font-size:28px;letter-spacing:.06em;color:var(--paper);
  }
  .demo{
    border:1px solid var(--line);border-radius:6px;padding:18px;
    display:flex;flex-direction:column;gap:16px;
  }
  .demo-cap{
    margin:0;font-size:14.5px;line-height:1.5;color:var(--paper);
    min-height:4.6em;max-width:58ch;
  }
  .demo-cap .stress{color:var(--ember)}
  .demo-stage{display:flex;gap:18px;align-items:flex-start;flex-wrap:wrap}
  .demo-grid{
    display:grid;grid-template-columns:repeat(5,1fr);gap:4px;
    width:min(100%,300px);flex-shrink:0;
  }
  .demo-side{display:flex;flex-direction:column;gap:10px;align-items:flex-start}
  .dcell{
    aspect-ratio:1;border:1px solid var(--line);border-radius:4px;
    background:var(--char);position:relative;
    display:flex;align-items:center;justify-content:center;
    font-family:'Staatliches',system-ui,sans-serif;
    font-size:clamp(15px,4.6vw,24px);line-height:1;color:var(--paper);
    transition:background-color .3s ease,color .3s ease;
  }
  .dcell.dspark{color:var(--flame);background:var(--char-2);text-shadow:0 0 10px rgba(255,216,107,.5)}
  .dcell.dclue{background:var(--char-2)}
  .dcell.dbreak{background:repeating-linear-gradient(135deg,#564b38 0 3px,#241f16 3px 9px);border-color:#6e6146}
  .dcell.dburn{background:var(--burn-bg,var(--ember));border-color:transparent;color:var(--soot);text-shadow:none}
  .dcell.dburn.dspark{color:#5a1d00}
  .dcell{transition:background-color .3s ease,color .3s ease,opacity .3s ease}
  .dcell.droute{outline:3px solid var(--paper);outline-offset:-1px;z-index:1}
  .dcell.dblocked{outline:3px dashed var(--danger);outline-offset:-1px;z-index:1}
  .demo-grid.focus .dcell{opacity:.3}
  .demo-grid.focus .dcell.droute,
  .demo-grid.focus .dcell.dblocked,
  .demo-grid.focus .dcell.dspark{opacity:1}
  .dcell.dx::before{
    content:"\2715";position:absolute;inset:0;display:flex;align-items:center;
    justify-content:center;color:var(--danger);
    font:700 1em/1 system-ui,sans-serif;
  }
  .dcell.ok::after{
    content:"\2713";position:absolute;top:1px;right:3px;
    font:700 11px/1 system-ui,sans-serif;color:var(--soot);opacity:.85;
  }
  .rulecols{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:20px}
  .rulecol{display:flex;flex-direction:column;gap:10px}
  .rulecol h3{
    margin:0;font-size:11px;letter-spacing:.18em;text-transform:uppercase;
    color:var(--ash-dim);font-weight:600;
  }
  .rulecol ol,.rulecol ul{
    margin:0;padding-left:20px;display:flex;flex-direction:column;gap:9px;
    font-size:14px;color:var(--ash);
  }
  .rulecol li strong{color:var(--paper);font-weight:600}
  @media (prefers-reduced-motion:reduce){.dcell{transition:none}}

  footer p{margin:0;font-size:12.5px;color:var(--ash-dim);max-width:58ch}

  /* ---------- toast ---------- */
  .toast{
    position:fixed;left:50%;bottom:26px;transform:translate(-50%,16px);
    background:var(--char-2);border:1px solid var(--line);border-left:3px solid var(--danger);
    color:var(--paper);padding:12px 16px;border-radius:5px;font-size:13.5px;
    max-width:min(88vw,420px);opacity:0;pointer-events:none;
    transition:opacity .25s ease,transform .25s ease;z-index:5;
  }
  .toast.show{opacity:1;transform:translate(-50%,0)}

  @media (prefers-reduced-motion:reduce){
    .cell{transition:none}
    .veil span{animation:none}
    .toast{transition:none}
  }
</style>
</head>
<body data-default-difficulty="{{ $defaultDifficulty }}">

<main>
  <header class="masthead">
    <p class="eyebrow">Incident report &middot; deduction puzzle</p>
    <h1>BURNFRONT<span class="spark-mark">★</span></h1>
    <p class="lede">The fire is out. The report says when it reached each numbered
    cell. Reconstruct the firebreaks that shaped its path — there is exactly one
    way, and pure logic finds it.</p>
  </header>

  <section class="board-wrap" aria-label="Puzzle board">
    <div class="toolbar">
      <div class="seg" role="group" aria-label="Difficulty">
        @foreach ($difficulties as $key => $config)
          <button type="button" data-diff="{{ $key }}" class="{{ $key === $defaultDifficulty ? 'on' : '' }}">{{ $config['label'] }}</button>
        @endforeach
      </div>
      <button type="button" class="btn primary" id="newBtn">New fire</button>
      <button type="button" class="btn" id="undoBtn" disabled>Undo</button>
      <button type="button" class="btn" id="resetBtn">Reset</button>
      <div class="chips">
        <div class="chip" id="breakChip"><span class="k">Breaks</span><span class="v" id="breakCount">0/0</span></div>
        <div class="chip"><span class="k">Time</span><span class="v" id="clock">0:00</span></div>
      </div>
    </div>
    <div style="position:relative;margin-top:14px">
      <div class="grid" id="grid" aria-label="Burnfront grid"></div>
      <div class="veil" id="veil"><span>Surveying terrain&hellip;</span></div>
    </div>
    <div class="under">
      <p class="hint" id="hint">Tap a cell to dig a firebreak &middot; tap again for a
      clear-ground dot &middot; a third tap erases. New here? The walkthrough below
      shows exactly how the fire moves.</p>
      <div class="banner" id="banner">
        <span class="headline">FIRE MAPPED</span>
        <p>Contained in <span class="v" id="finalTime">0:00</span> — every clue burns on time.</p>
      </div>
    </div>
  </section>

  <section class="learn" aria-label="How Burnfront works">
    <h2>HOW IT WORKS</h2>
    <div class="demo">
      <p class="demo-cap" id="demoCap" aria-live="polite"></p>
      <div class="demo-stage">
        <div class="demo-grid" id="demoGrid" aria-hidden="true"></div>
        <div class="demo-side">
          <div class="chip"><span class="k">Minute</span><span class="v" id="demoMin">0</span></div>
          <button type="button" class="btn" id="demoBtn">Pause</button>
        </div>
      </div>
    </div>
    <div class="rulecols">
      <div class="rulecol">
        <h3>The rules</h3>
        <ol>
          <li><strong>Shade exactly N firebreaks.</strong> The counter above the board sets N. The ★ and the numbered cells are never breaks.</li>
          <li><strong>Fire spreads one cell per minute.</strong> It starts on the ★ at minute 0 and moves up, down, left and right — never diagonally, never through a break.</li>
          <li><strong>Everything else burns.</strong> Every cell that isn&rsquo;t a firebreak must be reached by the fire eventually. No safe pockets.</li>
          <li><strong>Numbers are exact arrival times.</strong> A cell marked 5 caught fire at minute 5 — not before, not after.</li>
        </ol>
      </div>
      <div class="rulecol">
        <h3>Reading the numbers</h3>
        <ul>
          <li>A cell&rsquo;s minute is the length of the fire&rsquo;s <strong>shortest open route</strong> from the ★ — never less than the straight-line distance.</li>
          <li><strong>Bigger than the distance? Something is in the way.</strong> A 5 sitting 3 steps from the ★ proves every shorter route is blocked. That is how numbers reveal breaks.</li>
          <li>Neighboring burnt cells differ by at most 1, and a cell burning at minute t caught it from a neighbor that burned at t&minus;1 — wavefronts, not teleports.</li>
          <li><strong>Every break earns its place:</strong> open it, and the fire would reach some number too early. None hides in a corner justified by counting alone.</li>
          <li>Tap cycles firebreak &rarr; dot &rarr; empty. The dot is your own note for &ldquo;proven open&rdquo; — it isn&rsquo;t checked. The moment your Nth break lands, the board checks itself.</li>
        </ul>
      </div>
    </div>
  </section>

  <footer>
    <p>Every fire is generated on the Burnfront incident desk and machine-verified:
    exactly one valid placement of breaks, a solving path that needs no guessing,
    and no firebreak the clues can&rsquo;t justify.</p>
  </footer>
</main>

<div class="toast" id="toast" role="status"></div>

<script src="{{ asset('js/burnfront.js') }}"></script>
<script>
/* Animated walkthrough: a fixed 4x5 board, scripted as discrete "beats".
   Every beat re-renders the whole demo state, so pausing, stepping and
   looping are all trivially consistent. Static demo data — no engine
   dependency, so it isn't affected by moving generation server-side. */
(function(){
"use strict";
var R=4,C=5,SPARK=10,BREAKS=[12,7];
var TIMES=[2,3,4,5,6, 1,2,-1,6,7, 0,1,-1,5,6, 1,2,3,4,5];
var MAXT=7;
var CLUES={17:3,13:5};
var DIRECT=[11,12],XCELL=12;
var DETOUR=[15,16,17,18,13];

var CAPS=[
 'Fire starts on the ★ at minute 0 and spreads one cell per minute — up, down, left, right. <span class="stress">Firebreaks stop it dead.</span>',
 'Now read the 5: it sits only <span class="stress">3 steps</span> from the ★, yet it burned at minute 5. Every short route must be blocked.',
 'The fire went around instead — a <span class="stress">5-step route</span>, arriving at minute 5 exactly. The numbers record how the fire really traveled.',
 'In a real puzzle the firebreaks are <span class="stress">hidden</span>. The numbers are your only evidence.',
 'You shade the breaks that make every number exact. Each board has <span class="stress">exactly one answer</span> — and pure deduction finds it.'
];

/* beat: cap, t (wave minute, -1 = unburnt), vb (visible breaks), route/blocked, dur */
var BEATS=[
 {cap:0,t:0, vb:2,dur:2600},
 {cap:0,t:1, vb:2,dur:900},
 {cap:0,t:2, vb:2,dur:900},
 {cap:0,t:3, vb:2,dur:900},
 {cap:0,t:4, vb:2,dur:900},
 {cap:0,t:5, vb:2,dur:900},
 {cap:0,t:6, vb:2,dur:900},
 {cap:0,t:7, vb:2,dur:1600},
 {cap:1,t:7, vb:2,blocked:1,dur:4200},
 {cap:2,t:7, vb:2,route:1,dur:4600},
 {cap:3,t:-1,vb:0,dur:3400},
 {cap:3,t:-1,vb:1,dur:900},
 {cap:3,t:-1,vb:2,dur:1200},
 {cap:4,t:7, vb:2,dur:4800}
];

var grid=document.getElementById('demoGrid');
var cap=document.getElementById('demoCap');
var minEl=document.getElementById('demoMin');
var btn=document.getElementById('demoBtn');
var reduced=window.matchMedia('(prefers-reduced-motion: reduce)').matches;

var cells=[];
for(var i=0;i<R*C;i++){
  var d=document.createElement('div');
  d.className='dcell';
  var f=1-(0.25+0.6*(TIMES[i]<0?0:TIMES[i]/MAXT));
  var mix=function(a,c){return Math.round(c+(a-c)*f);};
  d.style.setProperty('--burn-bg','rgb('+mix(255,255)+','+mix(216,138)+','+mix(107,61)+')');
  grid.appendChild(d);
  cells.push(d);
}

function render(k){
  var b=BEATS[k];
  grid.classList.toggle('focus',!!(b.route||b.blocked));
  cap.innerHTML=CAPS[b.cap];
  minEl.textContent=b.t<0?'–':String(Math.min(b.t,MAXT));
  for(var i=0;i<R*C;i++){
    var d=cells[i],cls='dcell';
    var isBreak=BREAKS.indexOf(i)>=0;
    var shown=isBreak&&BREAKS.indexOf(i)<b.vb;
    if(i===SPARK)cls+=' dspark';
    if(CLUES[i]!==undefined)cls+=' dclue';
    if(shown)cls+=' dbreak';
    var burnt=!isBreak&&b.t>=0&&TIMES[i]<=b.t;
    if(burnt)cls+=' dburn';
    if(burnt&&CLUES[i]!==undefined)cls+=' ok';
    if(b.blocked&&DIRECT.indexOf(i)>=0)cls+=' dblocked';
    if(b.blocked&&i===XCELL)cls+=' dx';
    if(b.route&&DETOUR.indexOf(i)>=0)cls+=' droute';
    d.className=cls;
    d.textContent=i===SPARK?'★'
      :CLUES[i]!==undefined?String(CLUES[i])
      :burnt?String(TIMES[i]):'';
  }
}

var beat=0,timer=null,playing=false;
function show(k){beat=(k+BEATS.length)%BEATS.length;render(beat);}
function tickNext(){show(beat+1);schedule();}
function schedule(){
  clearTimeout(timer);
  if(playing)timer=setTimeout(tickNext,BEATS[beat].dur);
}
function setPlaying(p){
  playing=p;
  btn.textContent=p?'Pause':(reduced?'Next step':'Play');
  schedule();
}
var userPaused=false;
btn.addEventListener('click',function(){
  if(reduced){show(beat+1);return;}
  userPaused=playing;
  setPlaying(!playing);
});

show(0);
if(reduced){setPlaying(false);}
else{
  setPlaying(true);
  if('IntersectionObserver' in window){
    new IntersectionObserver(function(es){
      var vis=es[0].isIntersecting;
      if(!vis&&playing){setPlaying(false);}
      else if(vis&&!playing&&!userPaused){setPlaying(true);}
    },{threshold:0.25}).observe(grid);
  }
}
window.BurnfrontDemo={show:show,pause:function(){userPaused=true;setPlaying(false);},beats:BEATS.length};
})();
</script>

</body>
</html>
